import{_ as t,o as e,c as r,a2 as n}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Rumus Ketahanan Pangan — Brainstorm Index","description":"","frontmatter":{},"headers":[],"relativePath":"brainstorm/index.md","filePath":"brainstorm/index.md"}'),o={name:"brainstorm/index.md"};function i(s,a,d,l,c,p){return e(),r("div",null,[...a[0]||(a[0]=[n(`<h1 id="rumus-ketahanan-pangan-—-brainstorm-index" tabindex="-1">Rumus Ketahanan Pangan — Brainstorm Index <a class="header-anchor" href="#rumus-ketahanan-pangan-—-brainstorm-index" aria-label="Permalink to &quot;Rumus Ketahanan Pangan — Brainstorm Index&quot;">​</a></h1><p><strong>Owner:</strong> Paijo (BerkahKarya)<br><strong>Date:</strong> 2026-07-06<br><strong>Status:</strong> Active Strategy Document</p><hr><h2 id="apa-ini" tabindex="-1">Apa ini? <a class="header-anchor" href="#apa-ini" aria-label="Permalink to &quot;Apa ini?&quot;">​</a></h2><p>&quot;Rumus Ketahanan Pangan&quot; adalah metafora untuk <strong>income resilience</strong> — sistem yang menghasilkan, melindungi, dan melipatgandakan kapital secara otomatis via 6 workflow yang saling terhubung.</p><p>Dokumen-dokumen di sini adalah hasil brainstorm mendalam dari sesi 2026-07-06, mencakup desain teknis, definisi operasional, dan peta implementasi.</p><hr><h2 id="the-6-workflow-flywheel" tabindex="-1">The 6-Workflow Flywheel <a class="header-anchor" href="#the-6-workflow-flywheel" aria-label="Permalink to &quot;The 6-Workflow Flywheel&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  WF1: Content ──────────────────────────────────────┐</span></span>
<span class="line"><span>  WF2: Outreach ──────────────────────────────────────┤</span></span>
<span class="line"><span>  WF3: Products ──────────────────────────────────────┤──→ [CAPITAL POOL] ──→ WF5: Trading</span></span>
<span class="line"><span>  WF4: SaaS Sales ────────────────────────────────────┤    (1ai-hub)          (multiply ×)</span></span>
<span class="line"><span>  WF6: Arbitrage (Bootstrap) ─────────────────────────┘</span></span>
<span class="line"><span>                                                            ↑</span></span>
<span class="line"><span>                                                   Hermes GM (orchestration)</span></span>
<span class="line"><span>                                                            ↑</span></span>
<span class="line"><span>                                                    Vilona (strategic AI)</span></span></code></pre></div><p><strong>Insight kunci:</strong> Semua workflow deposit ke Capital Pool. Pool yang mendistribusikan ke trading atau reinvestment. Tanpa Pool, flywheel tidak berputar — ini prioritas #1.</p><hr><h2 id="status-setiap-workflow" tabindex="-1">Status Setiap Workflow <a class="header-anchor" href="#status-setiap-workflow" aria-label="Permalink to &quot;Status Setiap Workflow&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Workflow</th><th>Repo Utama</th><th>Tests</th><th>Deployed</th><th>Pool Connected</th><th>Score</th></tr></thead><tbody><tr><td><strong>WF1</strong> Content</td><td><code>1ai-content</code></td><td>?</td><td>Partial</td><td>❌</td><td>🟡 40%</td></tr><tr><td><strong>WF2</strong> Outreach</td><td><em>(belum ada)</em></td><td>❌</td><td>❌</td><td>❌</td><td>🔴 10%</td></tr><tr><td><strong>WF3</strong> Products</td><td><code>1ai-berkahkarya-website</code></td><td>?</td><td>Yes</td><td>❌</td><td>🟡 30%</td></tr><tr><td><strong>WF4</strong> SaaS Sales</td><td><code>1ai-trade-cex</code></td><td>975 ✅</td><td>Yes</td><td>❌</td><td>🟢 70%</td></tr><tr><td><strong>WF5</strong> Trading</td><td><code>1ai-trade-cex</code></td><td>975 ✅</td><td>Yes</td><td>❌</td><td>🟢 65%</td></tr><tr><td><strong>WF6</strong> Arbitrage</td><td><code>1ai-social/marketplace</code></td><td>32 ✅</td><td>❌</td><td>❌</td><td>🟡 55%</td></tr><tr><td><strong>Hermes GM</strong></td><td><code>.hermes/hermes-agent</code></td><td>?</td><td>Partial</td><td>❌</td><td>🟡 40%</td></tr><tr><td><strong>Capital Pool</strong></td><td><code>1ai-hub</code> <em>(to build)</em></td><td>❌</td><td>❌</td><td>N/A</td><td>🔴 <strong>0%</strong></td></tr></tbody></table><hr><h2 id="brainstorm-documents" tabindex="-1">Brainstorm Documents <a class="header-anchor" href="#brainstorm-documents" aria-label="Permalink to &quot;Brainstorm Documents&quot;">​</a></h2><h3 id="a-—-capital-pool-design" tabindex="-1"><a href="/brainstorm/a-capital-pool.html">A — Capital Pool Design</a> <a class="header-anchor" href="#a-—-capital-pool-design" aria-label="Permalink to &quot;[A — Capital Pool Design](/brainstorm/a-capital-pool)&quot;">​</a></h3><p>Database schema, service API, allocation logic (70/20/10 split), integrasi dengan semua workflow. <strong>Ini yang harus dibangun pertama.</strong></p><h3 id="b-—-wf6-arbitrage-engine" tabindex="-1"><a href="/brainstorm/b-wf6-concrete.html">B — WF6: Arbitrage Engine</a> <a class="header-anchor" href="#b-—-wf6-arbitrage-engine" aria-label="Permalink to &quot;[B — WF6: Arbitrage Engine](/brainstorm/b-wf6-concrete)&quot;">​</a></h3><p>WF6 bukan lagi &quot;vague middleman&quot; — ini concrete C2C arbitrage: produk apa, platform mana (OLX ↔ Facebook ↔ Carousell), margin berapa, volume target per bulan.</p><h3 id="c-—-hermes-gm-trigger-rules" tabindex="-1"><a href="/brainstorm/c-hermes-triggers.html">C — Hermes GM Trigger Rules</a> <a class="header-anchor" href="#c-—-hermes-gm-trigger-rules" aria-label="Permalink to &quot;[C — Hermes GM Trigger Rules](/brainstorm/c-hermes-triggers)&quot;">​</a></h3><p>4 level trigger: AUTO / NOTIFY / ESCALATE / EMERGENCY. Threshold lengkap untuk Capital Pool, trading bot, WF6 deals, content performance, system health.</p><h3 id="d-—-repo-→-workflow-map" tabindex="-1"><a href="/brainstorm/d-repo-map.html">D — Repo → Workflow Map</a> <a class="header-anchor" href="#d-—-repo-→-workflow-map" aria-label="Permalink to &quot;[D — Repo → Workflow Map](/brainstorm/d-repo-map)&quot;">​</a></h3><p>Ground truth: 30+ repos dipetakan ke 6 workflow. Mana yang sudah ada, mana yang overlap, mana yang gap. 5 file paling kritis diidentifikasi.</p><h3 id="e-—-content-outreach-cadence" tabindex="-1"><a href="/brainstorm/e-content-outreach.html">E — Content &amp; Outreach Cadence</a> <a class="header-anchor" href="#e-—-content-outreach-cadence" aria-label="Permalink to &quot;[E — Content &amp; Outreach Cadence](/brainstorm/e-content-outreach)&quot;">​</a></h3><p>WF1 + WF2 minimum viable cadence: 50 menit/minggu total. Content pillars, automation stack, outreach templates, 90-day plan.</p><hr><h2 id="priority-action-stack" tabindex="-1">Priority Action Stack <a class="header-anchor" href="#priority-action-stack" aria-label="Permalink to &quot;Priority Action Stack&quot;">​</a></h2><p>Berdasarkan semua brainstorm, urutan yang paling masuk akal:</p><ol><li><strong>Minggu 1-2:</strong> Build Capital Pool service di <code>1ai-hub</code> (<a href="/brainstorm/a-capital-pool.html#6-implementation-roadmap">detail →</a>)</li><li><strong>Minggu 2-3:</strong> Deploy <code>1ai-social/marketplace</code> ke production, close first 3 WF6 deals (<a href="/brainstorm/b-wf6-concrete.html#next-actions">detail →</a>)</li><li><strong>Minggu 3-4:</strong> Connect <code>1ai-trade-cex</code> PnL → Capital Pool (<a href="/brainstorm/d-repo-map.html#4-priority-repo-actions-by-workflow-impact">detail →</a>)</li><li><strong>Paralel:</strong> Setup PostBridge content automation + 5 content templates (<a href="/brainstorm/e-content-outreach.html">detail →</a>)</li><li><strong>Minggu 4-6:</strong> Load Hermes trigger rules, Vilona awareness (<a href="/brainstorm/c-hermes-triggers.html#9-implementation-plan">detail →</a>)</li></ol><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><ul><li><strong>Owner:</strong> Paijo a.k.a. Oyi77 / codergaboets</li><li><strong>Company:</strong> BerkahKarya (berkahkarya.org) — &quot;1 Man, Infinite Agents&quot;</li><li><strong>Architecture:</strong> Hermes GM (orchestration) + Vilona (AI strategic persona) + 1ai-hub (central brain)</li><li><strong>Stack:</strong> Python, TypeScript, Next.js, FastAPI, PostgreSQL, PM2, Telegram bots, Netlify</li></ul>`,32)])])}const g=t(o,[["render",i]]);export{m as __pageData,g as default};
